```plantuml
@startuml
title Class Diagram Title

interface IFoo {
    + void method()
}

abstract class Bar {
    <<static>> String name
    Foo foo
    # int x
    ~ int y
    - void method(String string)
}

class Qoo {
    Foo foo
}

class Foo {
    int x
    + void methodA()
}

Bar --|> IFoo : implements
Bar o-- Foo : Aggregation
Qoo *-- Foo : Composition

note right of Bar
    void method(String string){
        return string;
    }
end note

note bottom right
    public : +
    protected : #
    default : ~
    private : -
    Foo는 Bar가 Aggregation한다.(Bar -o Foo)
    Foo는 Qoo가 Composition한다.(Qoo -* Foo)
    Foo는 IFOoo를 상속한다.(Foo -|> IFoo)
end note

@enduml
